112	    public synchronized boolean enable(int type) {
113	        if (isReady()) {
114	            switch (type) {
115	                case JAVA:
116	                    return mJavaCrashHandler.enable();
117	                case NATIVE:
118	                    return nativeEnable();
119	            }
120	        }
121	        return false;
122	    }
