124	    public synchronized boolean disable(int type) {
125	        if (isReady()) {
126	            switch (type) {
127	                case JAVA:
128	                    return mJavaCrashHandler.disable();
129	                case NATIVE:
130	                    return nativeDisable();
131	            }
132	        }
133	        return false;
134	    }
