136	    public synchronized boolean isEnabled(int type) {
137	        if (isReady()) {
138	            switch (type) {
139	                case JAVA:
140	                    return mJavaCrashHandler.isEnabled();
141	                case NATIVE:
142	                    return nativeIsEnabled();
143	            }
144	        }
145	        return false;
146	    }
